public class WordCount {
    public static void main(String[] args) {
        System.out.println("Word count of 'Hello World': " + countWords("Hello World"));
        System.out.println("Word count of 'This is a test sentence': " + countWords("This is a test sentence"));
        System.out.println("Word count of '': " + countWords(""));
    }

    public static int countWords(String s) {
        if (s == null || s.trim().isEmpty()) {
            return 0;
        }
        String[] words = s.trim().split("\\s+");
        return words.length;
    }
}

public class Compress {
    public static void main(String[] args) {
        System.out.println("Compressed 'aaabbc': " + compress("aaabbc"));
        System.out.println("Compressed 'abc': " + compress("abc"));
        System.out.println("Compressed 'aaaa': " + compress("aaaa"));
    }

    public static String compress(String s) {
        if (s.isEmpty()) return "";

        StringBuilder sb = new StringBuilder();
        int i = 0;
        while (i < s.length()) {
            char c = s.charAt(i);
            int count = 0;
            while (i < s.length() && s.charAt(i) == c) {
                count++;
                i++;
            }
            sb.append(c).append(count);
        }
        return sb.toString();
    }
}

public class GenerateCSV {
    public static void main(String[] args) {
        String[] names = {"Aisha", "Raj", "Priya"};
        int[] ages = {28, 35, 24};
        String[] cities = {"Hyderabad", "Mumbai", "Bangalore"};

        System.out.println(toCsv(names, ages, cities));
    }

    public static String toCsv(String[] names, int[] ages, String[] cities) {
        StringBuilder sb = new StringBuilder();
        sb.append("Name,Age,City\n");

        for (int i = 0; i < names.length; i++) {
            sb.append(names[i]).append(",")
              .append(ages[i]).append(",")
              .append(cities[i]);
            if (i < names.length - 1) {
                sb.append("\n");
            }
        }

        return sb.toString();
    }
}

public class Caesar {
    public static void main(String[] args) {
        System.out.println("encrypt('Hello, World!', 3) = " + encrypt("Hello, World!", 3));
        System.out.println("encrypt('abc xyz', 2) = " + encrypt("abc xyz", 2));
    }

    public static String encrypt(String text, int shift) {
        StringBuilder sb = new StringBuilder();
        for (int i = 0; i < text.length(); i++) {
            char c = text.charAt(i);
            if (c >= 'a' && c <= 'z') {
                char shifted = (char) ((c - 'a' + shift) % 26 + 'a');
                sb.append(shifted);
            } else if (c >= 'A' && c <= 'Z') {
                char shifted = (char) ((c - 'A' + shift) % 26 + 'A');
                sb.append(shifted);
            } else {
                sb.append(c);
            }
        }
        return sb.toString();
    }
}
